entrypoint:
set -e
mkdir -p /mnt/openclaw-data
DATA_DIR="/mnt/openclaw-data/users/demo/main"
mkdir -p "$DATA_DIR/workspace" "$DATA_DIR/.npm-global" "$DATA_DIR/.npm-cache" "$DATA_DIR/extensions"
mkdir -p /home/node
if [ -e /home/node/.openclaw ] && [ ! -L /home/node/.openclaw ]; then
  rm -rf /home/node/.openclaw
fi
ln -sfn "$DATA_DIR" /home/node/.openclaw
chmod 755 "$DATA_DIR" "$DATA_DIR/workspace" "$DATA_DIR/.npm-global" "$DATA_DIR/.npm-cache" "$DATA_DIR/extensions" /home/node 2>/dev/null || true
export HOME=/home/node
export XDG_CONFIG_HOME=/home/node/.openclaw
export OPENCLAW_STATE_DIR=/home/node/.openclaw
export NPM_CONFIG_PREFIX="$DATA_DIR/.npm-global"
export NPM_CONFIG_CACHE="$DATA_DIR/.npm-cache"
export PATH="$NPM_CONFIG_PREFIX/bin:$PATH"
cat <<'EOF' > /home/node/.openclaw/openclaw.json
{
  "tools": {
    "allow": [
      "*"
    ],
    "profile": "full"
  },
  "agents": {
    "defaults": {
      "model": {
        "primary": "routin/mimo-v2-flash"
      },
      "workspace": "~/.openclaw/workspace"
    }
  },
  "models": {
    "mode": "merge",
    "providers": {
      "routin": {
        "api": "openai-completions",
        "apiKey": "${ROUTIN_API_KEY}",
        "models": [
          {
            "id": "mimo-v2-flash",
            "name": "Mimo V2 Flash",
            "input": [
              "text"
            ],
            "maxTokens": 32000,
            "reasoning": false,
            "contextWindow": 200000
          }
        ],
        "baseUrl": "https://api.routin.ai/v1"
      }
    }
  },
  "gateway": {
    "auth": {
      "mode": "token",
      "token": "oc_demo_65c0733045c347368742a27e6911b283"
    },
    "bind": "lan",
    "mode": "local",
    "controlUi": {
      "enabled": true,
      "dangerouslyDisableDeviceAuth": true,
      "dangerouslyAllowHostHeaderOriginFallback": true
    }
  }
}
EOF
exec node dist/index.js gateway --bind lan --port 18789

